import React, { useEffect, useState } from 'react';
import API from '../api/axios';
import { Bar, Doughnut } from 'react-chartjs-2';
import { Chart as ChartJS, CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend } from 'chart.js';
ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);

const StatCard = ({ icon, label, value, color }) => (
  <div style={{ ...styles.card, borderTop: `4px solid ${color}` }}>
    <div style={styles.cardIcon}>{icon}</div>
    <div style={{ ...styles.cardValue, color }}>{value}</div>
    <div style={styles.cardLabel}>{label}</div>
  </div>
);

export default function Dashboard() {
  const [leads, setLeads] = useState([]);
  const [properties, setProperties] = useState([]);
  const [dealStats, setDealStats] = useState({});

  useEffect(() => {
    API.get('/leads').then(r => setLeads(r.data)).catch(() => {});
    API.get('/properties').then(r => setProperties(r.data)).catch(() => {});
    API.get('/deals/stats/summary').then(r => setDealStats(r.data)).catch(() => {});
  }, []);

  const leadCounts = ['new','contacted','qualified','closed','lost'].map(s =>
    leads.filter(l => l.status === s).length
  );

  const propertyCounts = ['available','sold','rented'].map(s =>
    properties.filter(p => p.status === s).length
  );

  return (
    <div style={styles.page}>
      <h1 style={styles.title}>📊 Dashboard</h1>

      <div style={styles.statsGrid}>
        <StatCard icon="📋" label="Total Leads" value={leads.length} color="#3b82f6" />
        <StatCard icon="🏢" label="Properties" value={properties.length} color="#10b981" />
        <StatCard icon="🤝" label="Deals Closed" value={dealStats.closed_deals || 0} color="#8b5cf6" />
        <StatCard icon="💰" label="Total Revenue" value={`₹${Number(dealStats.total_revenue||0).toLocaleString()}`} color="#f59e0b" />
      </div>

      <div style={styles.chartsGrid}>
        <div style={styles.chartBox}>
          <h3 style={styles.chartTitle}>Lead Status</h3>
          <Bar data={{
            labels: ['New','Contacted','Qualified','Closed','Lost'],
            datasets: [{ label: 'Leads', data: leadCounts, backgroundColor: ['#3b82f6','#f59e0b','#10b981','#8b5cf6','#ef4444'] }]
          }} options={{ responsive: true, plugins: { legend: { display: false } } }} />
        </div>
        <div style={styles.chartBox}>
          <h3 style={styles.chartTitle}>Property Status</h3>
          <Doughnut data={{
            labels: ['Available','Sold','Rented'],
            datasets: [{ data: propertyCounts, backgroundColor: ['#10b981','#ef4444','#3b82f6'] }]
          }} options={{ responsive: true }} />
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: { padding: '24px' },
  title: { fontSize: '22px', fontWeight: '700', color: '#1e293b', marginBottom: '24px' },
  statsGrid: { display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '16px', marginBottom: '24px' },
  card: { background: '#fff', padding: '20px', borderRadius: '10px', boxShadow: '0 1px 8px rgba(0,0,0,0.08)' },
  cardIcon: { fontSize: '24px', marginBottom: '8px' },
  cardValue: { fontSize: '28px', fontWeight: '700' },
  cardLabel: { color: '#64748b', fontSize: '13px', marginTop: '4px' },
  chartsGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' },
  chartBox: { background: '#fff', padding: '20px', borderRadius: '10px', boxShadow: '0 1px 8px rgba(0,0,0,0.08)' },
  chartTitle: { fontSize: '15px', fontWeight: '600', color: '#1e293b', marginBottom: '16px' },
};
